	@Test
	void parseFallsBackToSlugifiedIdsAndNonBooleanOptionsStaySelects() {
		CreateTemplateConfig template = parse("synthetic", String.join("\n",
				"# @workbench.template label=\"Synthetic\" order=5",
				"[] <urn:test:p> \"{%###|value%}\" ;",
				"   <urn:test:q> \"{%Mode|true|maybe%}\" ."));

		assertThat(field(template, "###").getId()).isEqualTo("field");
		assertThat(field(template, "Mode").getControl()).isEqualTo(CreateTemplateConfig.FieldControl.SELECT);
	}

	@Test
	void propertyAndDefaultHelpersCoverFallbackBranches() {
		assertThat(invokeString("propertyToId", new Class<?>[] { String.class }, "not-a-prefixed-name"))
				.isEqualTo("not-a-prefixed-name");
		assertThat(invokeString("propertyToId", new Class<?>[] { String.class }, "config:"))
				.isEqualTo("config");
		assertThat(invokeString("defaultId", new Class<?>[] { String.class, String.class }, "", "%%%"))
				.isEqualTo("field");
		assertThat(invokeBoolean("isBooleanOptions", new Class<?>[] { List.class }, List.of("true"))).isFalse();
		assertThat(invokeBoolean("isBooleanOptions", new Class<?>[] { List.class }, List.of("true", "maybe")))
				.isFalse();
		assertThat(invokeInt("defaultRows", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXT)).isZero();
		assertThat(invokeInt("defaultCols", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXT)).isZero();
	}

	@Test
	void parseCoversInlineControlsFallbackMetadataAndBooleanHelpers() {
		CreateTemplateConfig template = parse("fallback-template", String.join("\n",
				"[] config:rep.id \"{%Identifier[control=radio]%}\" ;",
				"   rdfs:label \"{%Title[len=12]%}\" ;",
				"   config:description \"{%Description[rows=2,cols=9]%}\" ;",
				"   config:enabled \"{%Enabled|true|false%}\" ;",
				"   config:enabled-label \"{%Enabled%}\" ."));

		assertThat(template.getLabel()).isEqualTo("fallback-template");
		assertThat(template.getOrder()).isEqualTo(Integer.MAX_VALUE);
		assertThat(template.isHidden()).isFalse();
		assertThat(field(template, "Identifier").getControl()).isEqualTo(CreateTemplateConfig.FieldControl.RADIO);
		assertThat(field(template, "Title").getSize()).isEqualTo(12);
		assertThat(field(template, "Description").getRows()).isEqualTo(2);
		assertThat(field(template, "Description").getCols()).isEqualTo(9);
		assertThat(field(template, "Enabled").getControl()).isEqualTo(CreateTemplateConfig.FieldControl.RADIO);
		assertThat(field(template, "Enabled").getRole()).isEmpty();
		assertThat(field(template, "Enabled").getId()).isEqualTo("config_enabled");
		assertThat(invokeBoolean("isBooleanOptions", new Class<?>[] { List.class }, List.of("TRUE", "false"))).isTrue();
		assertThat(invokeInt("defaultRows", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXTAREA)).isEqualTo(8);
		assertThat(invokeInt("defaultCols", new Class<?>[] { CreateTemplateConfig.FieldControl.class },
				CreateTemplateConfig.FieldControl.TEXTAREA)).isEqualTo(80);
		assertThat(invokeString("propertyToId", new Class<?>[] { String.class }, "config:---"))
				.isEqualTo("config_field");
		Map<String, Integer> ids = new LinkedHashMap<>();
		assertThat(invokeString("uniqueId", new Class<?>[] { String.class, Map.class }, "config_enabled", ids))
				.isEqualTo("config_enabled");
		assertThat(invokeString("uniqueId", new Class<?>[] { String.class, Map.class }, "config_enabled", ids))
				.isEqualTo("config_enabled-2");
	}

	@Test
	void readTemplateThrowsForUnknownTemplateAndBuiltinDiscoveryReturnsKnownTypes() {
		assertThatThrownBy(() -> invoke("readTemplate", new Class<?>[] { String.class }, "definitely-missing-template"))
				.isInstanceOf(RuntimeException.class)
				.hasCauseInstanceOf(IOException.class)
				.hasMessageContaining("Could not load config template");
		assertThat(invokeList("discoverBuiltinTemplateTypes")).contains("memory", "native", "sparql");
	}

	@Test
	void reflectiveHelpersCoverNullNormalizationAndHiddenMetadataBranches() {
		CreateTemplateConfig template = parse("hidden-template", String.join("\n",
				"# @workbench.template label=\"Hidden\" order=9 hidden=true",
				"[] config:rep.id \"{%Repo Id%}\" ;",
				"   config:title \"{%Title[len=4,placeholder=hint]%}\" ."));

		assertThat(template.getLabel()).isEqualTo("Hidden");
		assertThat(template.getOrder()).isEqualTo(9);
		assertThat(template.isHidden()).isTrue();

		Object field = constructNested("Field", new Class<?>[] { String.class, String.class, String.class, String.class,
				CreateTemplateConfig.FieldControl.class, List.class, String.class, int.class, int.class, int.class,
				String.class }, "Name", "field-id", null, null, CreateTemplateConfig.FieldControl.TEXT, List.of("one"),
				null, 1, 2, 3, null);
		assertThat(readString(field, "property")).isEmpty();
		assertThat(readString(field, "role")).isEmpty();
		assertThat(readString(field, "defaultValue")).isEmpty();
		assertThat(readString(field, "placeholder")).isEmpty();

		Object hints = invokeNested("InlineHints", "parse", new Class<?>[] { String.class }, " ");
		assertThat(readString(hints, "placeholder")).isEmpty();

		Object fieldSpec = constructNested("FieldSpec",
				new Class<?>[] { String.class, hints.getClass(), String.class }, "Display", hints, null);
		assertThat(readString(fieldSpec, "property")).isEmpty();

		Object fieldName = invokeNested("FieldName", "parse", new Class<?>[] { String.class }, "[len=4]");
		assertThat(readString(fieldName, "displayName")).isEqualTo("[len=4]");

		assertThat(invoke("parseInteger", nestedClass("Metadata"), new Class<?>[] { String.class }, "")).isNull();
		assertThat(invoke("parseBoolean", nestedClass("Metadata"), new Class<?>[] { String.class }, "")).isNull();
	}

	@Test
	void parseCoversExplicitVisibleMetadataAndFileTemplateDiscoveryBranches() throws Exception {
		CreateTemplateConfig visible = parse("visible-template", String.join("\n",
				"# @workbench.template label=\"Visible\" order=1 hidden=false",
				"[] config:rep.id \"{%Repo Id%}\" ."));
		assertThat(visible.getOrder()).isEqualTo(1);
		assertThat(visible.isHidden()).isFalse();

		Path packageDir = tempDir.resolve("org/eclipse/rdf4j/repository/config");
		Files.createDirectories(packageDir);
		Files.writeString(packageDir.resolve("RepositoryConfig.class"), "");
		Files.writeString(packageDir.resolve("alpha.ttl"), "");
		Files.writeString(packageDir.resolve("beta.ttl"), "");
		Files.writeString(packageDir.resolve("ignore.txt"), "");

		assertThat(invokeList("discoverBuiltinTemplateTypes",
				new Class<?>[] { String.class, String.class },
				packageDir.resolve("RepositoryConfig.class").toUri().toString(),
				"org/eclipse/rdf4j/repository/config")).containsExactly("alpha", "beta");

		assertThatThrownBy(() -> invoke("discoverBuiltinTemplateTypes",
				new Class<?>[] { String.class, String.class },
				"ftp://example.org/RepositoryConfig.class",
				"org/eclipse/rdf4j/repository/config"))
				.isInstanceOf(RuntimeException.class)
				.hasCauseInstanceOf(IOException.class)
				.hasMessageContaining("Unsupported RepositoryConfig resource URI");

		assertThatThrownBy(() -> invoke("discoverBuiltinTemplateTypes",
				new Class<?>[] { String.class, String.class },
				"https://example.org/with space",
				"org/eclipse/rdf4j/repository/config"))
				.isInstanceOf(RuntimeException.class)
				.hasCauseInstanceOf(IOException.class)
				.hasMessageContaining("Could not resolve RepositoryConfig resources");
	}

